/*
 * KaTeX placeholder stub for offline / no-CDN deployment.
 *
 * This stub renders LaTeX as plain text so the platform works out-of-the-box
 * without an external download. To enable proper math rendering, replace this
 * file (and assets/katex.min.css + assets/fonts/) with the official KaTeX
 * 0.16.x release: https://github.com/KaTeX/KaTeX/releases (file: katex.tar.gz).
 *
 * Copy:
 *   katex/dist/katex.min.js  -> assets/katex.min.js
 *   katex/dist/katex.min.css -> assets/katex.min.css
 *   katex/dist/fonts/*       -> assets/fonts/
 *
 * Licence: MIT (https://github.com/KaTeX/KaTeX/blob/main/LICENSE).
 */
(function (root) {
  'use strict';
  function escape(s) {
    return String(s).replace(/[&<>"']/g, function (c) {
      return { '&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;' }[c];
    });
  }
  root.katex = {
    renderToString: function (tex, opts) {
      var disp = !!(opts && opts.displayMode);
      var cls = disp ? 'katex-stub block' : 'katex-stub inline';
      return '<span class="' + cls + '"><code>' + escape(tex) + '</code></span>';
    },
    render: function (tex, host, opts) {
      if (host) host.innerHTML = root.katex.renderToString(tex, opts);
    }
  };
})(typeof window !== 'undefined' ? window : this);
